# Mixed typed and untyped methods and fields
field Int $typed_field = 42;
field $untyped_field = "hello";

method typed_method(Str $input) -> Str {
    return uc($input);
}

sub untyped_sub {
    my ($param) = @_;
    return $param * 2;
}

method partially_typed($untyped, Int $typed) -> Str {
    return "$untyped: $typed";
}
